import { useState } from 'react';
import {
    Box,
    Button,
    Grid,
    Typography,
    IconButton,
    Card,
    CardMedia,
} from '@mui/material';
import {
    Add as AddIcon,
    Delete as DeleteIcon,
} from '@mui/icons-material';
import PhotoBookPage from './PhotoBookPage';

const PhotoBookPages = ({ format, availablePhotos, pages, onPagesChange }) => {
    const [selectedPhotos, setSelectedPhotos] = useState([]);

    const handleAddPage = () => {
        onPagesChange([...pages, { photos: [] }]);
    };

    const handleDeletePage = (pageIndex) => {
        const newPages = pages.filter((_, index) => index !== pageIndex);
        onPagesChange(newPages);
    };

    const handlePhotoAdd = (pageIndex, position, photo) => {
        const newPages = [...pages];
        const page = newPages[pageIndex];
        if (page) {
            page.photos = [
                ...page.photos.filter(p => p.position !== position),
                { ...photo, position }
            ];
            onPagesChange(newPages);
            setSelectedPhotos(prev => [...prev, photo.id]);
        }
    };

    const handlePhotoRemove = (pageIndex, position) => {
        const newPages = [...pages];
        const page = newPages[pageIndex];
        if (page) {
            const removedPhoto = page.photos.find(p => p.position === position);
            if (removedPhoto) {
                setSelectedPhotos(prev => prev.filter(id => id !== removedPhoto.id));
            }
            page.photos = page.photos.filter(p => p.position !== position);
            onPagesChange(newPages);
        }
    };

    const handlePhotoEdit = (pageIndex, position, editedPhoto) => {
        const newPages = [...pages];
        const page = newPages[pageIndex];
        if (page) {
            const photoIndex = page.photos.findIndex(p => p.position === position);
            if (photoIndex !== -1) {
                page.photos[photoIndex] = {
                    ...page.photos[photoIndex],
                    ...editedPhoto
                };
                onPagesChange(newPages);
            }
        }
    };

    return (
        <Box sx={{ width: '100%', p: 2 }}>
            <Box sx={{ mb: 4 }}>
                <Typography variant="h5" gutterBottom align="center">
                    Создание страниц фотокниги
                </Typography>
                <Typography variant="subtitle1" color="text.secondary" gutterBottom align="center">
                    Перетащите фотографии на страницы
                </Typography>
            </Box>

            <Grid container spacing={2}>
                <Grid item xs={12} md={3}>
                    <Typography variant="h6" gutterBottom>
                        Доступные фотографии
                    </Typography>
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                        {availablePhotos
                            .filter(photo => !selectedPhotos.includes(photo.id))
                            .map((photo) => (
                                <Card
                                    key={photo.id}
                                    sx={{ width: 100, height: 100 }}
                                    draggable
                                    onDragStart={(e) => {
                                        e.dataTransfer.setData('photo', JSON.stringify(photo));
                                    }}
                                >
                                    <CardMedia
                                        component="img"
                                        image={photo.url}
                                        alt={`Photo ${photo.id}`}
                                        sx={{ height: '100%', objectFit: 'cover' }}
                                    />
                                </Card>
                            ))}
                    </Box>
                </Grid>

                <Grid item xs={12} md={9}>
                    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                        {pages.map((page, index) => (
                            <Box key={index} sx={{ position: 'relative' }}>
                                <PhotoBookPage
                                    format={format}
                                    photos={page.photos}
                                    onPhotoAdd={(position, photo) => handlePhotoAdd(index, position, photo)}
                                    onPhotoRemove={(position) => handlePhotoRemove(index, position)}
                                    onPhotoEdit={(position, photo) => handlePhotoEdit(index, position, photo)}
                                />
                                {index > 0 && (
                                    <IconButton
                                        size="small"
                                        onClick={() => handleDeletePage(index)}
                                        sx={{ position: 'absolute', top: 8, right: 8 }}
                                    >
                                        <DeleteIcon />
                                    </IconButton>
                                )}
                            </Box>
                        ))}
                        <Button
                            variant="outlined"
                            startIcon={<AddIcon />}
                            onClick={handleAddPage}
                            sx={{ alignSelf: 'center' }}
                        >
                            Добавить страницу
                        </Button>
                    </Box>
                </Grid>
            </Grid>
        </Box>
    );
};

export default PhotoBookPages;
